INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000001', E'포장재 단가 비교해봤어요', E'핸드드로잉 일러스트 굿즈 포장용 크래프트 봉투, 스티커, 끈 등 단가 비교 정리. 대량 구매하면 30% 절감 가능해요.', '자유게시판', 'seller', E'윤서연', false, NULL, 30, true, NOW() - interval '16 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000002', E'가죽 키링·카드지갑 재료 어디서 구매하시나요?', E'온라인으로만 사다가 오프라인 도매상도 가보고 싶은데 추천 부탁드려요. 서울 기준이면 더 좋아요!', '자유게시판', 'seller', E'박유나', false, NULL, 20, true, NOW() - interval '43 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000003', E'브랜드 네이밍 고민 중이에요', E'지금 향기미니로 활동 중인데 좀 더 컨셉이 명확한 이름으로 바꿀까 고민입니다. 다들 어떻게 정하셨나요?', '자유게시판', 'seller', E'손승현', false, NULL, 4, true, NOW() - interval '59 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000004', E'루비바닐라 신상 컬렉션 나왔어요!', E'아로마 캔들 작가입니다. 이번엔 러블리 스타일로 새 컬렉션 작업했어요. 인스타 들러주세요 :)', '자유게시판', 'seller', E'이시현', false, NULL, 76, true, NOW() - interval '46 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000005', E'[현장] 성수 마켓 분위기 좋아요', E'차분라일락 부스 운영 중! 사람 많고 분위기 최고예요. 마크라메 벽장식 인기 폭발!', '실시간 행사 현황', 'seller', E'손수민', false, NULL, 8, true, NOW() - interval '37 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000005', E'마크라메 벽장식 재료 어디서 구매하시나요?', E'온라인으로만 사다가 오프라인 도매상도 가보고 싶은데 추천 부탁드려요. 서울 기준이면 더 좋아요!', '자유게시판', 'seller', E'손수민', false, NULL, 39, true, NOW() - interval '57 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000006', E'카드 단말기 뭐 쓰세요?', E'소담리리입니다. 토스, 페이코, KIS 비교 중인데 수수료랑 사용감 어떤가요?', '자유게시판', 'seller', E'심지민', false, NULL, 14, true, NOW() - interval '48 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000006', E'[현장] 잠실 마켓 분위기 좋아요', E'소담리리 부스 운영 중! 사람 많고 분위기 최고예요. 비누 꽃다발 인기 폭발!', '실시간 행사 현황', 'seller', E'심지민', false, NULL, 28, true, NOW() - interval '32 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000007', E'포장재 단가 비교해봤어요', E'캘리그라피 엽서·문구 포장용 크래프트 봉투, 스티커, 끈 등 단가 비교 정리. 대량 구매하면 30% 절감 가능해요.', '자유게시판', 'seller', E'허민준', false, NULL, 15, true, NOW() - interval '9 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000007', E'플리마켓 첫 참가 후기', E'저는 캘리그라피 엽서·문구 만드는 소담루비예요. 경력 5년차, 단골 손님 위주로 운영합니다. 첫 마켓 참가했는데 정말 떨렸어요. 그래도 단골손님 한 분 생겨서 행복합니다.', '자유게시판', 'seller', E'허민준', false, NULL, 62, true, NOW() - interval '28 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000008', E'포장재 단가 비교해봤어요', E'뜨개 모자·머플러 포장용 크래프트 봉투, 스티커, 끈 등 단가 비교 정리. 대량 구매하면 30% 절감 가능해요.', '자유게시판', 'seller', E'이보민', false, NULL, 47, true, NOW() - interval '14 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000008', E'솔직히 부스비 너무 비싸요', E'뜨개 모자·머플러 작가인데 부스비 빼면 거의 안 남아요. 다들 어떻게 버티세요?', '익명', 'seller', NULL, true, E'익명523', 10, true, NOW() - interval '35 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000009', E'주최사에 항의해도 답이 없어요', E'자리 변경 요청드렸는데 무시당했어요. 이런 경우 어디에 문의하나요?', '익명', 'seller', NULL, true, E'익명118', 77, true, NOW() - interval '44 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000010', E'레진 코스터·트레이 재료 어디서 구매하시나요?', E'온라인으로만 사다가 오프라인 도매상도 가보고 싶은데 추천 부탁드려요. 서울 기준이면 더 좋아요!', '자유게시판', 'seller', E'오민지', false, NULL, 4, true, NOW() - interval '32 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000010', E'플리마켓 첫 참가 후기', E'저는 레진 코스터·트레이 만드는 차분나무예요. 풀타임 작가로 전국 마켓 다니며 활동합니다. 첫 마켓 참가했는데 정말 떨렸어요. 그래도 단골손님 한 분 생겨서 행복합니다.', '자유게시판', 'seller', E'오민지', false, NULL, 30, true, NOW() - interval '11 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000011', E'봄날온유 신상 컬렉션 나왔어요!', E'왁스 타블렛 작가입니다. 이번엔 미니멀 스타일로 새 컬렉션 작업했어요. 인스타 들러주세요 :)', '자유게시판', 'seller', E'전보민', false, NULL, 23, true, NOW() - interval '49 days');
INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e1000000-0000-0000-0000-000000000012', E'향기차분 신상 컬렉션 나왔어요!', E'우드 도마·소반 작가입니다. 이번엔 내추럴 스타일로 새 컬렉션 작업했어요. 인스타 들러주세요 :)', '자유게시판', 'seller', E'황수빈', false, NULL, 35, true, NOW() - interval '46 days');
