INSERT INTO public.posts (user_id, title, content, category, seller_type, author, is_anonymous, anonymous_name, likes, is_mock, created_at) VALUES ('e2000000-0000-0000-0000-000000000005', E'주최사 자리 배정 너무 불공정', E'크림 파스타 트럭인데 늘 외진 자리만 받아요. 어떻게 항의해야 할지...', '익명', 'foodtruck', NULL, true, E'익명782', 70, true, NOW() - interval '5 days');
